// ML-01 + ML-03 Integration: ot04 Evaluate Outcomes
// Tracks IC (ML-01) AND updates Bayesian priors (ML-03) from actual outcomes

function _sgNode(name) {
  try {
    return $(name).first().json || {};
  } catch (e) {
    return {};
  }
}

const tickerRaw = _sgNode('Fetch BTC Price');
const tickerResult = tickerRaw && tickerRaw.result ? tickerRaw.result : {};
const tickerKey = Object.keys(tickerResult)[0];
const ticker = tickerResult[tickerKey] || {};
const currentPrice = ticker.c ? parseFloat(ticker.c[0]) : 0;

const vaultRaw = _sgNode('Read Vault Signals');
const memories = (vaultRaw && vaultRaw.memories) ? vaultRaw.memories : [];

let correct = 0, incorrect = 0, neutral = 0, evaluated = 0;
const outcomes = [];
const gradeable = [];
const outcomesByRegime = {};

// Parse vault signals and grade outcomes
for (const mem of memories) {
  const content = mem.content || '';
  const dirMatch = content.match(/TRADE SIGNAL[^:]*:\s*(BUY|SELL|WAIT)/);
  const priceMatch = content.match(/@\s*\$(\d+(?:\.\d+)?)/);
  const confMatch = content.match(/Conf:\s*([\d.]+)%/);
  const regimeMatch = content.match(/Regime:(\w+)/);

  if (!dirMatch || !priceMatch) continue;

  const dir = dirMatch[1];
  const signalPrice = parseFloat(priceMatch[1]);
  const conf = confMatch ? parseFloat(confMatch[1]) : 0;
  const regime = regimeMatch ? regimeMatch[1] : 'UNKNOWN';

  if (dir === 'WAIT') {
    neutral++;
    evaluated++;
    continue;
  }

  if (currentPrice === 0 || signalPrice === 0) continue;

  const pctMove = ((currentPrice - signalPrice) / signalPrice) * 100;
  let outcome;

  if (Math.abs(pctMove) < 0.3) {
    outcome = 'TOO_SOON';
  } else if (dir === 'BUY' && pctMove > 0) {
    outcome = 'CORRECT';
    correct++;
  } else if (dir === 'SELL' && pctMove < 0) {
    outcome = 'CORRECT';
    correct++;
  } else {
    outcome = 'INCORRECT';
    incorrect++;
  }

  evaluated++;
  const outcomeObj = {
    dir,
    signalPrice,
    currentPrice: Math.round(currentPrice),
    pctMove: Math.round(pctMove * 100) / 100,
    conf,
    outcome,
    regime
  };
  outcomes.push(outcomeObj);
  gradeable.push(outcomeObj);

  // Track outcomes by regime for prior updates (ML-03)
  if (!outcomesByRegime[regime]) {
    outcomesByRegime[regime] = { outcomes: [], correct: 0, total: 0 };
  }
  outcomesByRegime[regime].outcomes.push(outcomeObj);
  outcomesByRegime[regime].total++;
  if (outcome === 'CORRECT') {
    outcomesByRegime[regime].correct++;
  }
}

// ============================================================================
// ML-01: INFORMATION COEFFICIENT CALCULATION
// ============================================================================

function spearmanIC(pairs) {
  if (pairs.length < 3) return 0;

  const confRanked = pairs
    .map((p, i) => ({ idx: i, val: p.confidence }))
    .sort((a, b) => a.val - b.val)
    .map((p, rank) => ({ idx: p.idx, rank }));

  const returnRanked = pairs
    .map((p, i) => ({ idx: i, val: p.return }))
    .sort((a, b) => a.val - b.val)
    .map((p, rank) => ({ idx: p.idx, rank }));

  const diffs = confRanked.map(c => {
    const returnRank = returnRanked.find(r => r.idx === c.idx).rank;
    return (c.rank - returnRank) ** 2;
  });

  const sumD2 = diffs.reduce((a, b) => a + b, 0);
  const n = pairs.length;
  const rho = 1 - (6 * sumD2) / (n * (n * n - 1));
  return rho;
}

const icPairs = gradeable.map(o => ({
  confidence: o.conf,
  return: o.outcome === 'CORRECT' ? 1 : 0
}));

const ic = spearmanIC(icPairs);
const icBps = Math.round(ic * 1000) / 10;

const icInterpretation =
  ic > 0.05 ? 'EXCELLENT_EDGE' :
  ic > 0.02 ? 'GOOD_INVESTABLE' :
  ic > 0.0 ? 'WEAK_POSITIVE' :
  ic > -0.02 ? 'NO_CORRELATION' :
  'NEGATIVE_CORRELATION';

const icHistory = ($getWorkflowStaticData('ic_history') || {});
const historyKey = `ic_${new Date().toISOString().slice(0, 10)}`;

if (!icHistory[historyKey]) {
  icHistory[historyKey] = [];
}
icHistory[historyKey].push(ic);

if (icHistory[historyKey].length > 10) {
  icHistory[historyKey] = icHistory[historyKey].slice(-10);
}

$setWorkflowStaticData('ic_history', icHistory);

const recentIC = icHistory[historyKey].slice(-4);
const allWeak = recentIC.length === 4 && recentIC.every(x => x < 0.02);
let demotionFlag = false;

if (gradeable.length >= 10) {
  if (allWeak || ic < -0.02) {
    demotionFlag = true;
  }
}

// ============================================================================
// ML-03: BAYESIAN PRIOR UPDATES (Laplace Smoothing)
// ============================================================================
// Update priors based on actual win rates per regime
// Formula: P_new = (wins + α) / (total + 2α) where α=1

const LAPLACE_ALPHA = 1;

// Read existing priors from static data
const ml03Data = $getWorkflowStaticData('ml03_bayesian_priors') || {};
let priorUpdates = {};
let updateCount = 0;

// For each regime with outcomes, calculate updated prior
for (const regime in outcomesByRegime) {
  const regimeData = outcomesByRegime[regime];
  if (regimeData.total >= 10) {
    // Only update if sufficient sample (10+ trades for this regime)
    const newPrior = (regimeData.correct + LAPLACE_ALPHA) / (regimeData.total + 2 * LAPLACE_ALPHA);
    priorUpdates[regime] = {
      prior: Math.round(newPrior * 10000) / 10000,
      winRate: regimeData.correct / regimeData.total,
      samples: regimeData.total,
      correctCount: regimeData.correct
    };
    updateCount++;
    console.log(`[ML-03] Updated ${regime}: ${regimeData.correct}/${regimeData.total} correct → prior=${newPrior.toFixed(4)}`);
  }
}

// Store all priors (learned + defaults)
const defaultPriors = {
  BULL_TREND_STRONG:0.72,
  BULL_TREND_WEAK:0.60,
  BEAR_TREND_STRONG:0.28,
  BEAR_TREND_WEAK:0.40,
  RANGE_BOUND:0.50,
  BREAKOUT_BULL:0.68,
  BREAKOUT_BEAR:0.32,
  HIGH_VOL_EXPAND:0.50,
  LOW_VOL_COMPRESS:0.50,
  RISK_ON:0.65,
  RISK_OFF:0.38,
  EXTREME_CAUTION:0.42
};

const allPriors = Object.assign({}, defaultPriors);
for (const regime in priorUpdates) {
  allPriors[regime] = priorUpdates[regime].prior;
}

// Save updated priors to static data
if (updateCount > 0) {
  ml03Data.priors = allPriors;
  ml03Data.lastUpdate = new Date().toISOString();
  ml03Data.sampleCount = (ml03Data.sampleCount || 0) + gradeable.length;
  ml03Data.regimeUpdates = priorUpdates;
  $setWorkflowStaticData('ml03_bayesian_priors', ml03Data);
  console.log(`[ML-03] Persisted ${updateCount} regime priors to static data`);
}

// ============================================================================
// BUILD OUTPUT
// ============================================================================

const total = correct + incorrect;
const avgConf = outcomes.length > 0 ? Math.round((outcomes.reduce((s, o) => s + o.conf, 0) / outcomes.length) * 10) / 10 : 0;

const summary = `OUTCOME REPORT | ${new Date().toISOString().slice(0, 16)}Z
BTC @ $${Math.round(currentPrice)}
Signals evaluated: ${evaluated} | Correct: ${correct} | Incorrect: ${incorrect} | Neutral: ${neutral}
Hit Rate: ${total > 0 ? Math.round((correct / total) * 100) : 0}% | Avg Confidence: ${avgConf}%
IC: ${icBps} bps (${icInterpretation}) | ML-03: ${updateCount} regime(s) updated`;

return [
  {
    json: {
      summary,
      hitRate: total > 0 ? Math.round((correct / total) * 100) : 0,
      correct,
      incorrect,
      neutral,
      evaluated,
      currentPrice,
      avgConf,
      outcomes: outcomes.slice(0, 10),
      // ML-01: IC Metrics
      ic: Math.round(ic * 10000) / 10000,
      icBps,
      icInterpretation,
      icHistory: icHistory[historyKey] || [],
      demotionTriggered: demotionFlag,
      // ML-03: Prior Updates
      ml03UpdateCount: updateCount,
      ml03RegimeUpdates: priorUpdates,
      ml03AllPriors: allPriors,
      ml03SampleCount: ml03Data.sampleCount || 0
    }
  }
];

